export function AccountLogo({
  name,
  domain,
  size = 24,
  variant = 'token',
  width = 92,
  height = 24,
  className,
}: {
  name: string | null | undefined
  domain: string | null | undefined
  size?: number
  variant?: 'token' | 'full'
  width?: number
  height?: number
  className?: string
}) {
  const [failed, setFailed] = useState(false)
  const host = rootDomain(domain)

  if (!LOGODEV_TOKEN || !host || failed) {
    return <NameAvatar name={name} size={size} className={className} />
  }

  const src =
    variant === 'full'
      ? `https://img.logo.dev/${host}?token=${LOGODEV_TOKEN}&width=${width}&height=${height}&format=png&theme=light&retina=true&fallback=404`
      : `https://img.logo.dev/${host}?token=${LOGODEV_TOKEN}&size=${size * 2}&format=png&retries=0`

  if (variant === 'full') {
    return (
      <img
        src={src}
        alt=""
        aria-hidden
        width={width}
        height={height}
        onError={() => setFailed(true)}
        className={className}
        style={{
          width,
          height,
          maxWidth: '100%',
          objectFit: 'contain',
          objectPosition: 'left center',
          flexShrink: 0,
        }}
      />
    )
  }

export function AccountRelationLogo({
  value,
  accountById,
  size = 24,
  variant = 'full',
  width = 92,
  height = 24,
  className,
}: {
  value: RelationValue
  accountById?: Map<string, Retailer>
  size?: number
  variant?: 'full' | 'token' | 'token-name'
  width?: number
  height?: number
  className?: string
}) {
  const account = accountById?.get(relationId(value))
  const name = relatedName(account ?? value)
  if (name === '—') {
    return <span className={cn('text-muted-foreground', className)}>—</span>
  }

  const domain = relationDomain(value) ?? account?.domain ?? null

  return (
    <span
      className={cn('inline-flex min-w-0 items-center align-middle', variant === 'token-name' && 'gap-2', className)}
      title={name}
      aria-label={name}
    >
      <AccountLogo
        name={name}
        domain={domain}
        size={size}
        variant={variant === 'full' ? 'full' : 'token'}
        width={width}
        height={height}
      />
      {variant === 'token-name' ? (
        <span className="min-w-0 truncate font-[500] text-foreground">{name}</span>
      ) : (
        <span className="sr-only">{name}</span>
      )}
    </span>
  )

